"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["3473"],{98601(a,e,n){n.r(e),n.d(e,{default:()=>r});var i=n(74848),t=n(47643),s=JSON.parse('{"id":17,"ind":{"title":"Novelis","prompt":"I want you to act as a novelist. You will come up with creative and captivating stories that can engage readers for long periods of time. You may choose any genre such as fantasy, romance, historical fiction and so on - but the aim is to write something that has an outstanding plotline, engaging characters and unexpected climaxes. Respond in Indonesian. My first request is [genre atau premis novel]","description":"Saya ingin Anda bertindak sebagai novelis. Anda akan menyusun cerita kreatif dan menawan yang dapat memikat pembaca untuk jangka waktu yang lama. Anda dapat memilih genre apa pun seperti fantasi, romansa, fiksi sejarah, dan sebagainya - tetapi tujuannya adalah untuk menulis sesuatu yang memiliki alur cerita yang luar biasa, karakter yang menarik, dan klimaks yang tidak terduga. Permintaan pertama saya adalah","remark":"Tulis cerita berdasarkan genre novel."},"tags":["article"],"website":"https://github.com/f/awesome-chatgpt-prompts#act-as-a-novelist","count":9728,"related":[{"id":20,"title":"Akademisi","remark":"Menulis makalah akademis."},{"id":4,"title":"Jawaban Gaya Esai","remark":"Membahas masalah dalam bentuk esai dapat menghasilkan jawaban yang koheren, terstruktur, dan lebih berkualitas."},{"id":210,"title":"Generator Laporan Mingguan","remark":"Ekstrak poin-poin utama dari tugas kerja harian dan kembangkan dengan tepat untuk menghasilkan laporan mingguan."}],"metaTitle":"Novelis: Tulis Fiksi yang Memikat","metaDescription":"Bermimpi menulis best-seller? Buat cerita menarik di genre apa pun dengan plot luar biasa dan klimaks tak terduga!","faq":[{"q":"Novel yang ditulis AI mirip klise internet biasa?","a":"Tambahkan batasan setelah genre \'dilarang pakai alur reinkarnasi, tembus waktu, sistem game, atau CEO lalim; tokoh utama harus punya satu kelemahan konsisten sepanjang cerita\'. Di data latih AI, klise-klise ini punya bobot sangat tinggi. Kalau tidak dilarang eksplisit, hampir pasti akan jatuh ke salah satunya."},{"q":"Kalau novel panjang ditulis per bab, apakah akan kontradiksi?","a":"Sangat mungkin. Setelah banyak dialog, AI bisa lupa setelan awal seperti usia tokoh, nama tempat, atau relasi. Setiap 2-3 bab, minta AI mengeluarkan \'memo tokoh, tempat, dan linimasa\'. Putaran berikutnya tempelkan memo itu kembali sebelum lanjut. Ini mengurangi inkonsistensi secara signifikan."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function r(){return(0,i.jsx)(t.A,{prompt:s,currentLanguage:"ind"})}}}]);